    std::cout << "  Classic 'ding-ding' coin collect sound.\n\n";
    for (int i = 0; i < 3; i++) {
        std::cout << "  ▶ Playing... (" << (i+1) << "/3)\r";
        std::cout.flush();
        audio.playSound("coin");
        sleepMs(500);
    }
    std::cout << "\n";
    printPrompt();
    if (!waitForUser()) return 0;

    // ===================================================================
    // Test 6: DAMAGE (low thud)
