    printHeader("Test 10: Background Music");
    std::cout << "  Procedural background music loop (16 seconds, 140 BPM).\n";
    std::cout << "  Melody (pentatonic) + bass + chords + percussion.\n\n";
    std::cout << "  Starting music...\n";
    audio.startMusic();
